import {
  HTMLAttributes,
  useCallback,
  useEffect,
  useState,
  useRef,
} from 'preact/compat';
import { ProductList as ProductListComponent } from '@/recommendations/components';
import { Container, Slot, SlotProps } from '@adobe-commerce/elsie/lib';
import { useText } from '@adobe-commerce/elsie/i18n';
import {
  Button,
  Image,
  ImageProps,
  Price,
  PriceRange,
  ProductItemCard,
} from '@adobe-commerce/elsie/components';
import { Item, RecommendationUnitModel } from '@/recommendations/data/models';
import { events } from '@adobe-commerce/event-bus';
import { getRecommendationsByUnitIds } from '@/recommendations/api';
import type { CurrentProduct } from '@/recommendations/api/getRecommendationsByUnitIds/getRecommendationsByUnitIds';
import {
  publishRecsItemClick,
  publishRecsUnitRender,
  publishRecsUnitView,
} from '@/recommendations/lib/acdl/publish';

export interface ProductListProps extends HTMLAttributes<HTMLDivElement> {
  recId: string;
  initialData?: {
    recommendations?: {
      results: RecommendationUnitModel[];
      totalProducts: number;
    };
  };
  hideHeading?: boolean;
  routeProduct?: (item: Item) => string;
  /** @deprecated Pass `currentProduct` with `sku` instead. Kept for backward compatibility. */
  currentSku?: string;
  /** Current product SKU and optional price for recommendation filtering. */
  currentProduct?: CurrentProduct;
  cartSkus?: string[];
  userPurchaseHistory?: any[];
  userViewHistory?: any[];
  pagePlacement?: string | '';
  slots?: {
    Heading?: SlotProps;
    Footer?: SlotProps;
    Title?: SlotProps<{
      item: Item;
      productUrl: string;
    }>;
    Sku?: SlotProps<{
      item: Item;
    }>;
    Price?: SlotProps<{
      item: Item;
    }>;
    Thumbnail?: SlotProps<{
      item: any;
      defaultImageProps: ImageProps;
    }>;
  };
}

export const ProductList: Container<ProductListProps> = ({
  recId,
  initialData = null,
  hideHeading,
  routeProduct,
  currentSku: currentSkuProp,
  currentProduct: currentProductProp,
  cartSkus,
  userPurchaseHistory,
  userViewHistory,
  pagePlacement,
  slots,
  ...props
}) => {
  const currentSku = currentProductProp?.sku ?? currentSkuProp ?? '';

  const [loading, setLoading] = useState(!initialData);

  const [recommendations, setRecommendations] = useState<
    RecommendationUnitModel[] | null
  >(
    initialData?.recommendations?.results
      ? initialData.recommendations.results.filter(
        (unit) => unit.unitId === recId
      )
      : []
  );

  const containerRef = useRef<HTMLDivElement>(null);
  const dictionary = useText({
    addToCartText: 'Recommendations.ProductList.addToCart',
    optionsText: 'Recommendations.ProductList.selectOptions',
    viewProductText: 'Recommendations.ProductList.viewProduct',
  });

  const hasRequiredData = useCallback((): boolean => {
    return !!recId;
  }, [recId]);

  useEffect(() => {
    const dataEvent = events.on(
      'recommendations/data',
      (payload: RecommendationUnitModel[] | null) => {
        if (payload && payload.length > 0 && payload.some((unit) => unit.unitId === recId)) {
          setRecommendations((prev) => {
            const existing = prev || [];
            //log any userError for the matching recId
            payload.forEach((unit) => {
              if (unit.unitId === recId && unit.userError) {
                console.error(`${unit.userError}`);
              }
            });
            
            const newUnits = payload.filter(
              (unit) =>
                unit?.unitId === recId &&
                unit?.items?.length &&
                !existing.some((e) => e.unitId === unit.unitId)
            );

            // Trigger render event for each new valid unit
            newUnits.forEach((unit) => {
              publishRecsUnitRender({
                recommendationUnit: unit,
                pagePlacement: 'product-list',
                yOffsetTop:
                  containerRef.current?.getBoundingClientRect().top ?? 0,
                yOffsetBottom:
                  containerRef.current?.getBoundingClientRect().bottom ?? 0,
                backupProducts: 0,
                searchTime: 0,
              });
            });

            return [...existing, ...newUnits];
          });
        }
        setLoading(false);
      }
    );

    return () => {
      dataEvent?.off();
    };
  }, [recId]);

  // Add intersection observer for view events
  useEffect(() => {
    if (!recommendations?.length || !containerRef.current) return;

    const intersectionObserverOptions = {
      root: null,
      rootMargin: '0px',
      threshold: 0.5,
    };

    const handleIntersection = (entries: IntersectionObserverEntry[]) => {
      entries.forEach((entry) => {
        if (entry.intersectionRatio > 0.5) {
          recommendations.forEach((unit) => {
            publishRecsUnitView({
              recommendationUnit: unit,
              pagePlacement: 'product-list',
              yOffsetTop:
                containerRef.current?.getBoundingClientRect().top ?? 0,
              yOffsetBottom:
                containerRef.current?.getBoundingClientRect().bottom ?? 0,
            });
          });
        }
      });
    };

    const observer = new IntersectionObserver(
      handleIntersection,
      intersectionObserverOptions
    );
    observer.observe(containerRef.current);

    return () => observer.disconnect();
  }, [recommendations]);

  useEffect(() => {
    // Only fetch recommendations if we have all required data
    if (!hasRequiredData()) {
      setLoading(false);
      return;
    }

    setLoading(true);
    getRecommendationsByUnitIds({
      currentSku,
      cartSkus,
      userPurchaseHistory,
      userViewHistory,
      unitIds: [recId],
      currentProduct: currentProductProp,
    }).catch((error) => {
      console.error('Recommendations error:', error);
      setRecommendations([]);
      setLoading(false);
    });
  }, [
    currentSku,
    cartSkus,
    userPurchaseHistory,
    userViewHistory,
    hasRequiredData,
    recId,
    currentProductProp,
  ]);

  if (!hasRequiredData()) {
    if (!recId) {
      console.warn(
        'ProductList: recId is missing. Please provide a valid recId to display product recommendations.'
      );
    }
    return null;
  }

  const getImage = (
    item: RecommendationUnitModel['items'][0],
    index: number
  ) => {
    const defaultImageProps: ImageProps = {
      loading: index < 4 ? 'eager' : 'lazy',
      src: item.images?.[0]?.url || '',
      alt: item.images?.[0]?.label || '',
      width: '300',
      height: '300',
      params: { width: 300 },
    };

    const imageComponent = (
      <Image
        data-testid="product-list-item-image"
        {...defaultImageProps}
        aria-label={item.sku}
      />
    );

    return (
      <Slot
        name="Thumbnail"
        slot={slots?.Thumbnail}
        context={{
          item,
          defaultImageProps,
        }}
      >
        {routeProduct ? (
          <a href={routeProduct(item)}>{imageComponent}</a>
        ) : (
          imageComponent
        )}
      </Slot>
    );
  };

  const heading = (
    <Slot name="Heading" slot={slots?.Heading} context={{ recommendations }}>
      <div data-testid="default-product-list-heading">
        {recommendations?.[0]?.title || dictionary.heading}
      </div>
    </Slot>
  );

  const getFooter = (
    item: RecommendationUnitModel['items'][0],
    index: number
  ) => {
    return (
      <Slot
        name="Footer"
        slot={slots?.Footer}
        context={{
          item,
          index,
        }}
      >
        <div data-testid="default-product-list-footer">
          {routeProduct && (
            <a href={routeProduct(item)}>
              <Button
                data-testid="default-product-list-footer-button"
                children={dictionary.viewProductText}
                aria-label={dictionary.viewProductText}
                variant="primary"
              />
            </a>
          )}
        </div>
      </Slot>
    );
  };

  const getTitle = (item: RecommendationUnitModel['items'][0]) => {
    return (
      <Slot
        name="Title"
        slot={slots?.Title}
        context={{
          item,
          productUrl: routeProduct ? routeProduct(item) : '',
        }}
      >
        {routeProduct ? (
          <a href={routeProduct(item)}>{item.name}</a>
        ) : (
          <span>{item.name}</span>
        )}
      </Slot>
    );
  };

  const getSku = (item: RecommendationUnitModel['items'][0]) => {
    return (
      <Slot
        name="Sku"
        slot={slots?.Sku}
        context={{
          item,
        }}
      >
        <span>{item.sku}</span>
      </Slot>
    );
  };

  const getPrice = (item: RecommendationUnitModel['items'][0]) => {
    return (
      <Slot
        name="Price"
        slot={slots?.Price}
        context={{
          item,
        }}
      >
        <div data-testid="default-product-price">
          {item.itemType === 'ComplexProductView' ? (
            <PriceRange
              display="from to"
              minimumAmount={item.priceRange?.minimum?.final?.amount?.value}
              maximumAmount={item.priceRange?.maximum?.final?.amount?.value}
              currency={item.priceRange?.minimum?.final?.amount?.currency}
            />
          ) : (
            <Price
              amount={item.price.final?.amount?.value}
              currency={item.price.final?.amount?.currency}
            />
          )}
        </div>
      </Slot>
    );
  };

  const handleProductClick = (
    item: RecommendationUnitModel['items'][0],
    productId: number
  ) => {
    const recommendationUnit = recommendations?.find((unit) =>
      unit.items?.some((unitItem) => unitItem.sku === item.sku)
    );
    if (recommendationUnit) {
      publishRecsItemClick({
        recommendationUnit,
        pagePlacement: pagePlacement || '',
        yOffsetTop: containerRef.current?.getBoundingClientRect().top ?? 0,
        yOffsetBottom:
          containerRef.current?.getBoundingClientRect().bottom ?? 0,
        productId,
      });
    }
  };

  const productEntries = recommendations?.[0]?.totalProducts ? (
    <>
      {recommendations?.map(
        ({ items, totalProducts }: RecommendationUnitModel, unitIndex) =>
          totalProducts > 0
            ? items.map(
              (item: RecommendationUnitModel['items'][0], index: number) => {
                const { sku } = item;

                return (
                  <span
                    key={sku}
                    role="group"
                    aria-label={`Product ${unitIndex * items.length + index + 1
                      } of ${totalProducts}`}
                    onClick={() =>
                      handleProductClick(
                        item,
                        unitIndex * items.length + index
                      )
                    }
                  >
                    <ProductItemCard
                      data-testid="recommendations-product-item-card"
                      initialized
                      sku={getSku(item)}
                      image={getImage(item, unitIndex * items.length + index)}
                      titleNode={getTitle(item)}
                      price={getPrice(item)}
                      actionButton={getFooter(
                        item,
                        unitIndex * items.length + index
                      )}
                    />
                  </span>
                );
              }
            )
            : null
      )}
    </>
  ) : null;

  const isEmpty =
    !recommendations ||
    recommendations.length === 0 ||
    recommendations.every((unit) => !unit.items || unit.items.length === 0);

  return (
    <div ref={containerRef}>
      <ProductListComponent
        {...props}
        className={isEmpty ? 'recommendations-product-list--empty' : ''}
        heading={hideHeading ? undefined : heading}
        loading={loading}
        products={
          isEmpty ? null : (
            <div className="recommendations-carousel__content">
              {productEntries}
            </div>
          )
        }
      />
    </div>
  );
};
